const incoming = $input.first()?.json ?? {};

const payload = {
  tenant_id: 'atos-lab',
  source: 'wazuh',
  alert_id: 'WAZUH-SSH-000001',
  timestamp: '2026-06-18T14:32:15Z',
  severity: 'medium',
  correlation_id: null,
  agent: {
    id: '001',
    name: 'srv-linux-01',
    ip: '10.10.20.15'
  },
  rule: {
    id: '5710',
    level: 10,
    description: 'Multiple SSH authentication failures detected',
    groups: [
      'authentication_failed',
      'sshd',
      'bruteforce'
    ]
  },
  event: {
    event_type: 'ssh_bruteforce',
    username: 'admin',
    src_ip: '203.0.113.55',
    dst_ip: '10.10.20.15',
    protocol: 'ssh',
    port: 22,
    failed_attempts: 37
  },
  threat_context: {
    known_malicious: false,
    ioc_present: true,
    ioc_type: 'ip',
    ioc_value: '203.0.113.55'
  },
  mitre: {
    tactic: 'Credential Access',
    technique: 'Brute Force',
    technique_id: 'T1110'
  },
  investigation: {
    status: 'new',
    approval_required: false
  },
  raw_log: 'Failed password for admin from 203.0.113.55 port 51234 ssh2',
  created_at: '2026-06-18T14:32:15Z'
};

if (incoming.mock_alert_id) {
  payload.alert_id = incoming.mock_alert_id;
}

return [{ json: payload }];

const body = $input.first().json;

const requiredFields = ['tenant_id', 'source', 'alert_id', 'timestamp'];
const missing = requiredFields.filter((field) => body[field] === undefined || body[field] === null || body[field] === '');

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error_type: 'validation_error',
      message: 'Missing required fields',
      missing_fields: missing,
      received_payload: body
    }
  }];
}

return [{
  json: {
    valid: true,
    received_payload: body
  }
}];

const payload = $input.first().json.received_payload;
const now = new Date();
const timestamp = now.toISOString();
const random = Math.random().toString(36).slice(2, 10);
const safeAlertId = String(payload.alert_id).replace(/[^a-zA-Z0-9_-]/g, '-');

const correlationId = payload.correlation_id || `corr-${now.getTime()}-${random}`;
const investigationId = `inv-${now.getTime()}-${safeAlertId}`;
const executionId = `exec-${now.getTime()}-${random}`;

const normalized = {
  tenant_id: payload.tenant_id || 'default',
  source: payload.source,
  alert_id: payload.alert_id,
  timestamp: payload.timestamp,
  correlation_id: correlationId,
  investigation_id: investigationId,
  execution_id: executionId,
  severity_original: payload.severity || payload.rule?.level || 'unknown',
  rule_id: payload.rule?.id || null,
  rule_name: payload.rule?.description || null,
  src_ip: payload.event?.src_ip || null,
  dst_ip: payload.event?.dst_ip || payload.agent?.ip || null,
  hostname: payload.agent?.name || payload.event?.hostname || null,
  username: payload.event?.username || null,
  raw_payload: payload,
  redis_key: `soc:investigation:${payload.tenant_id || 'default'}:${payload.source}:${payload.alert_id}`,
  received_at: timestamp,
  workflow_mode: 'mock'
};

return [{ json: normalized }];

return $input.all().map((item) => {
  const current = item.json;
  const duplicate = current.alert_id === 'WAZUH-SSH-000001-DUPLICATE';

  return {
    json: {
      ...current,
      duplicate
    }
  };
});

return $input.all().map((item) => {
  const current = item.json;

  return {
    json: {
      ...current,
      redis_mock: {
        stored: true,
        ttl: 3600
      }
    }
  };
});

return $input.all().map((item) => {
  const current = item.json;

  return {
    json: {
      ...current,
      postgres_mock: {
        inserted: true,
        table: 'soc_alerts',
        alert_uuid: 'mock-alert-uuid'
      }
    }
  };
});

const current = $input.first().json;

return [{
  json: {
    status: 'accepted',
    accepted: true,
    duplicate: false,
    tenant_id: current.tenant_id,
    source: current.source,
    alert_id: current.alert_id,
    correlation_id: current.correlation_id,
    investigation_id: current.investigation_id,
    redis_key: current.redis_key,
    next_stage: 'ai_analysis_pending',
    production_status: 'mock_intake_completed'
  }
}];
